import React, { useState, useEffect } from 'react';

// Base64 encoded logo for artifact sandbox compatibility
const LOGO_BASE64 = "data:image/webp;base64,";

const MitLivMedCarousel = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isAutoPlaying, setIsAutoPlaying] = useState(true);
  const [language, setLanguage] = useState('da');

  const content = {
    da: {
      header: "Kan du genkende det?",
      quotes: [
        "Jeg er så træt af at forklare mig til folk, der ikke forstår.",
        "Det er ikke episoderne, der slider mig ned. Det er hverdagen imellem.",
        "Jeg har googlet mig gennem alt. Det meste er støj — eller direkte skadeligt.",
        "Jeg vil gerne tro på, at det bliver bedre. Men ikke hvis det føles som en løgn.",
        "Nogle gange har jeg bare brug for at vide, at nogen har stået her før mig."
      ],
      transition: "Det er ikke dig, der er forkert. Det er hullet efter behandlingen.",
      facts: [
        {
          stat: "42-51%",
          text: "bliver sendt hjem uden opfølgning den første måned — netop når risikoen er størst.",
          highlight: "Tidlig kontakt reducerer den risiko med 18%.",
          footnote: 1
        },
        {
          stat: "1 ud af 5",
          text: "opnår meningsfuld bedring gennem peer-støtte.",
          highlight: "Effekter der holder i mindst 6-9 måneder.",
          footnote: 2
        }
      ],
      closing: "Det her er ikke tomme ord. Det er dokumenteret, og det er derfor, vi bygger MitLivMed.",
      cta: "Kom i gang",
      footnotes: [
        { text: 'Stein BD, et al. "Outpatient Follow-up After Psychiatric Hospitalization." PMC, 2021.', url: 'https://pmc.ncbi.nlm.nih.gov/articles/PMC8695636/' },
        { text: 'Høgh Egmose C, et al. Copenhagen Research Center for Mental Health. Psychiatric Services, 2023.', url: 'https://pubmed.ncbi.nlm.nih.gov/36751908/' }
      ],
      langSwitch: "English"
    },
    en: {
      header: "Does this sound familiar?",
      quotes: [
        "I'm so tired of explaining myself to people who don't get it.",
        "It's not the episodes that wear me down. It's the everyday in between.",
        "I've googled my way through everything. Most of it is noise — or actually harmful.",
        "I want to believe it gets better. But not if it feels like a lie.",
        "Sometimes I just need to know someone's been here before me."
      ],
      transition: "It's not you that's broken. It's the gap after treatment.",
      facts: [
        {
          stat: "42-51%",
          text: "are sent home without follow-up in the first month — right when the risk is highest.",
          highlight: "Early connection reduces that risk by 18%.",
          footnote: 1
        },
        {
          stat: "1 in 5",
          text: "achieve meaningful recovery through peer support.",
          highlight: "Effects that last at least 6-9 months.",
          footnote: 2
        }
      ],
      closing: "This isn't empty hope. It's documented — and it's why we built MitLivMed.",
      cta: "Get started",
      footnotes: [
        { text: 'Stein BD, et al. "Outpatient Follow-up After Psychiatric Hospitalization." PMC, 2021.', url: 'https://pmc.ncbi.nlm.nih.gov/articles/PMC8695636/' },
        { text: 'Høgh Egmose C, et al. Copenhagen Research Center for Mental Health. Psychiatric Services, 2023.', url: 'https://pubmed.ncbi.nlm.nih.gov/36751908/' }
      ],
      langSwitch: "Dansk"
    }
  };

  const c = content[language];
  const totalSlides = c.quotes.length + 1 + c.facts.length + 1;
  const lastSlideIndex = totalSlides - 1;

  useEffect(() => {
    if (!isAutoPlaying) return;
    
    // Longer pause on last slide (CTA) before looping
    const duration = currentSlide === lastSlideIndex ? 8000 : 3000;
    
    const timer = setTimeout(() => {
      setCurrentSlide((prev) => (prev + 1) % totalSlides);
    }, duration);
    return () => clearTimeout(timer);
  }, [isAutoPlaying, currentSlide, lastSlideIndex, totalSlides]);

  const goToSlide = (index) => {
    setCurrentSlide(index);
    setIsAutoPlaying(true);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % totalSlides);
    setIsAutoPlaying(false);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + totalSlides) % totalSlides);
    setIsAutoPlaying(false);
  };

  const getSlideContent = () => {
    // Quotes (0-4)
    if (currentSlide < c.quotes.length) {
      return (
        <div className="flex flex-col items-center justify-center min-h-64 px-6 text-center">
          <div className="text-6xl opacity-20 mb-4" style={{ color: '#F58220', fontFamily: 'Georgia, serif' }}>"</div>
          <p className="text-xl md:text-2xl lg:text-3xl font-light leading-relaxed max-w-2xl italic" style={{ color: '#2D2D2D', fontFamily: 'Inter, sans-serif', lineHeight: 1.7 }}>
            {c.quotes[currentSlide]}
          </p>
          <div className="text-6xl opacity-20 mt-4 rotate-180" style={{ color: '#F58220', fontFamily: 'Georgia, serif' }}>"</div>
        </div>
      );
    }
    
    // Transition slide
    if (currentSlide === c.quotes.length) {
      return (
        <div className="flex flex-col items-center justify-center min-h-64 px-6 text-center">
          <div className="w-16 h-px mb-8" style={{ background: 'linear-gradient(to right, transparent, #F58220, transparent)' }}></div>
          <p className="text-2xl md:text-3xl lg:text-4xl font-semibold leading-tight max-w-2xl" style={{ color: '#2C5F63', fontFamily: 'Satoshi, sans-serif' }}>
            {c.transition}
          </p>
          <div className="w-16 h-px mt-8" style={{ background: 'linear-gradient(to right, transparent, #F58220, transparent)' }}></div>
        </div>
      );
    }
    
    // Facts
    const factIndex = currentSlide - c.quotes.length - 1;
    if (factIndex < c.facts.length) {
      const fact = c.facts[factIndex];
      return (
        <div className="flex flex-col items-center justify-center min-h-64 px-6 text-center">
          <div className="text-5xl md:text-6xl lg:text-7xl font-bold mb-4 tracking-tight" style={{ color: '#F58220', fontFamily: 'Satoshi, sans-serif' }}>
            {fact.stat}
          </div>
          <p className="text-lg md:text-xl max-w-xl mb-4" style={{ color: '#5A5A5A', fontFamily: 'Inter, sans-serif', lineHeight: 1.7 }}>
            {fact.text}
          </p>
          <p className="text-lg md:text-xl font-medium max-w-xl mb-6" style={{ color: '#2C5F63', fontFamily: 'Inter, sans-serif' }}>
            {fact.highlight}
          </p>
          {/* Inline footnote */}
          <div className="max-w-lg px-4 py-3 rounded-lg" style={{ backgroundColor: 'rgba(245, 130, 32, 0.06)' }}>
            <p className="text-xs" style={{ color: '#8A8A8A', fontFamily: 'Inter, sans-serif', lineHeight: 1.5 }}>
              <sup className="mr-1" style={{ color: '#F58220' }}>{fact.footnote}</sup>
              {c.footnotes[fact.footnote - 1].text}{' '}
              <a 
                href={c.footnotes[fact.footnote - 1].url}
                target="_blank"
                rel="noopener noreferrer"
                className="underline transition-colors"
                style={{ color: '#F58220' }}
                onMouseEnter={(e) => e.target.style.color = '#2C5F63'}
                onMouseLeave={(e) => e.target.style.color = '#F58220'}
              >
                {language === 'da' ? 'Kilde' : 'Source'} ↗
              </a>
            </p>
          </div>
        </div>
      );
    }
    
    // Closing slide
    return (
      <div className="flex flex-col items-center justify-center min-h-64 px-6 text-center">
        <p className="text-xl md:text-2xl lg:text-3xl font-medium leading-relaxed max-w-2xl mb-8" style={{ color: '#2D2D2D', fontFamily: 'Satoshi, sans-serif', lineHeight: 1.5 }}>
          {c.closing}
        </p>
        <button 
          className="px-8 py-4 font-semibold rounded-full transition-all duration-300 hover:scale-105 shadow-lg"
          style={{ 
            backgroundColor: '#F58220', 
            color: '#FDFBF7',
            fontFamily: 'Satoshi, sans-serif',
            boxShadow: '0 4px 14px rgba(245, 130, 32, 0.3)'
          }}
        >
          {c.cta}
        </button>
      </div>
    );
  };

  const getSlideType = () => {
    if (currentSlide < c.quotes.length) return 'quote';
    if (currentSlide === c.quotes.length) return 'transition';
    if (currentSlide < c.quotes.length + 1 + c.facts.length) return 'fact';
    return 'closing';
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden" style={{ backgroundColor: '#FDFBF7', fontFamily: 'Inter, sans-serif' }}>
      
      {/* Film grain texture overlay */}
      <div 
        className="fixed inset-0 pointer-events-none z-50"
        style={{
          backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E")`,
          opacity: 0.02,
        }}
      />

      {/* Subtle gradient background */}
      <div 
        className="fixed inset-0 pointer-events-none"
        style={{
          background: `radial-gradient(ellipse at 50% 0%, rgba(245, 130, 32, 0.04) 0%, transparent 50%)`,
        }}
      />

      {/* Header with logo and language toggle */}
      <header className="relative z-20 flex items-center justify-between px-6 py-6">
        <div className="flex items-center gap-3">
          <img 
            src={LOGO_BASE64} 
            alt="MitLivMed" 
            className="h-12 w-auto"
          />
          <span className="text-xl font-semibold tracking-tight" style={{ color: '#3D2E1F', fontFamily: '"Reddit Sans", sans-serif' }}>
            MitLivMed
          </span>
        </div>
        <button
          onClick={() => setLanguage(language === 'da' ? 'en' : 'da')}
          className="px-4 py-2 text-sm transition-colors rounded-full border"
          style={{ 
            color: '#5A5A5A', 
            borderColor: '#E8D5B5',
            fontFamily: 'Inter, sans-serif'
          }}
          onMouseEnter={(e) => {
            e.target.style.borderColor = '#F58220';
            e.target.style.color = '#F58220';
          }}
          onMouseLeave={(e) => {
            e.target.style.borderColor = '#E8D5B5';
            e.target.style.color = '#5A5A5A';
          }}
        >
          {c.langSwitch}
        </button>
      </header>

      {/* Main content */}
      <div className="flex-1 flex flex-col items-center justify-center relative z-10 py-8 md:py-16">
        
        {/* Section header */}
        <div className={`mb-8 md:mb-12 transition-all duration-500 ${getSlideType() === 'quote' ? 'opacity-100' : 'opacity-40'}`}>
          <h2 
            className="text-2xl md:text-3xl lg:text-4xl font-medium tracking-wide"
            style={{ color: '#2D2D2D', fontFamily: 'Satoshi, sans-serif' }}
          >
            {c.header}
          </h2>
        </div>

        {/* Carousel container */}
        <div 
          className="w-full max-w-4xl relative px-4"
          onMouseEnter={() => setIsAutoPlaying(false)}
          onMouseLeave={() => setIsAutoPlaying(true)}
        >
          {/* Slide content */}
          <div className="relative overflow-hidden">
            <div 
              key={currentSlide}
              style={{ animation: 'fadeIn 0.6s ease-out' }}
            >
              {getSlideContent()}
            </div>
          </div>

          {/* Navigation arrows */}
          <button
            onClick={prevSlide}
            className="absolute left-0 top-1/2 -translate-y-1/2 p-3 transition-colors"
            style={{ color: '#D4D9C1' }}
            onMouseEnter={(e) => e.target.style.color = '#F58220'}
            onMouseLeave={(e) => e.target.style.color = '#D4D9C1'}
            aria-label="Previous slide"
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <button
            onClick={nextSlide}
            className="absolute right-0 top-1/2 -translate-y-1/2 p-3 transition-colors"
            style={{ color: '#D4D9C1' }}
            onMouseEnter={(e) => e.target.style.color = '#F58220'}
            onMouseLeave={(e) => e.target.style.color = '#D4D9C1'}
            aria-label="Next slide"
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>

        {/* Progress indicators */}
        <div className="flex items-center gap-2 mt-8 md:mt-12">
          {Array.from({ length: totalSlides }).map((_, index) => {
            let type = 'quote';
            if (index === c.quotes.length) type = 'transition';
            else if (index > c.quotes.length && index < c.quotes.length + 1 + c.facts.length) type = 'fact';
            else if (index >= c.quotes.length + 1 + c.facts.length) type = 'closing';
            
            const isActive = currentSlide === index;
            const isFactOrTransition = type === 'fact' || type === 'transition';
            
            return (
              <button
                key={index}
                onClick={() => goToSlide(index)}
                className="transition-all duration-300 rounded-full"
                style={{
                  width: isActive ? '2rem' : '0.5rem',
                  height: '0.5rem',
                  backgroundColor: isActive 
                    ? (isFactOrTransition ? '#F58220' : '#2C5F63')
                    : (isFactOrTransition ? 'rgba(245, 130, 32, 0.3)' : '#D4D9C1')
                }}
                aria-label={`Go to slide ${index + 1}`}
              />
            );
          })}
        </div>

        {/* Auto-play indicator */}
        <div className="mt-4 text-xs" style={{ color: '#A0A0A0', fontFamily: 'Inter, sans-serif' }}>
          {isAutoPlaying ? (
            <span className="flex items-center gap-2">
              <span 
                className="w-1.5 h-1.5 rounded-full animate-pulse"
                style={{ backgroundColor: '#F58220' }}
              />
              {language === 'da' ? 'Automatisk afspilning' : 'Auto-playing'}
            </span>
          ) : (
            <span style={{ color: '#C0C0C0' }}>
              {language === 'da' ? 'Sat på pause' : 'Paused'}
            </span>
          )}
        </div>
      </div>

      {/* Keyframes */}
      <style>{`
        @import url('https://api.fontshare.com/v2/css?f[]=satoshi@400,500,700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Reddit+Sans:wght@400;500;600;700&display=swap');
        
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(8px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
};

export default MitLivMedCarousel;
